126→function skipAuras(r: PacketReader): void {
127→  const lo = r.uint32LE();
128→  const hi = r.uint32LE();
129→  for (let i = 0; i < 32; i++) {
130→    if (lo & (1 << i)) {
131→      r.uint32LE();
132→      r.uint8();
133→    }
134→  }
135→  for (let i = 0; i < 32; i++) {
136→    if (hi & (1 << i)) {
137→      r.uint32LE();
138→      r.uint8();
139→    }
140→  }
141→}
