144→  r: PacketReader,
145→  isFull = false,
146→): PartyMemberStats {
147→  if (isFull) r.uint8();
148→  const { low: guidLow, high: guidHigh } = r.packedGuid();
149→  const mask = r.uint32LE();
150→  const result: PartyMemberStats = { guidLow, guidHigh };
151→
152→  if (mask & GroupUpdateFlag.STATUS) {
153→    const status = r.uint16LE();
154→    result.online = (status & 0x01) !== 0;
155→  }
156→  if (mask & GroupUpdateFlag.CUR_HP) result.hp = r.uint32LE();
157→  if (mask & GroupUpdateFlag.MAX_HP) result.maxHp = r.uint32LE();
158→  if (mask & GroupUpdateFlag.POWER_TYPE) r.uint8();
159→  if (mask & GroupUpdateFlag.CUR_POWER) r.uint16LE();
160→  if (mask & GroupUpdateFlag.MAX_POWER) r.uint16LE();
161→  if (mask & GroupUpdateFlag.LEVEL) result.level = r.uint16LE();
162→  if (mask & GroupUpdateFlag.ZONE) r.uint16LE();
163→  if (mask & GroupUpdateFlag.POSITION) {
164→    r.uint16LE();
165→    r.uint16LE();
166→  }
167→  if (mask & GroupUpdateFlag.AURAS) skipAuras(r);
168→  if (mask & GroupUpdateFlag.PET_GUID) {
169→    r.uint32LE();
170→    r.uint32LE();
171→  }
172→  if (mask & GroupUpdateFlag.PET_NAME) r.cString();
173→  if (mask & GroupUpdateFlag.PET_MODEL_ID) r.uint16LE();
174→  if (mask & GroupUpdateFlag.PET_CUR_HP) r.uint32LE();
175→  if (mask & GroupUpdateFlag.PET_MAX_HP) r.uint32LE();
176→  if (mask & GroupUpdateFlag.PET_POWER_TYPE) r.uint8();
177→  if (mask & GroupUpdateFlag.PET_CUR_POWER) r.uint16LE();
178→  if (mask & GroupUpdateFlag.PET_MAX_POWER) r.uint16LE();
179→  if (mask & GroupUpdateFlag.PET_AURAS) skipAuras(r);
180→  if (mask & GroupUpdateFlag.VEHICLE_SEAT) r.uint32LE();
181→
182→  return result;
